import{_ as a,o as e,c as o,a2 as l}from"./chunks/framework.CuEaBji2.js";const g=JSON.parse('{"title":"排障指南","description":"","frontmatter":{},"headers":[],"relativePath":"operations/troubleshooting.md","filePath":"operations/troubleshooting.md","lastUpdated":1782021666000}'),r={name:"operations/troubleshooting.md"};function i(n,t,s,h,d,p){return e(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="排障指南" tabindex="-1">排障指南 <a class="header-anchor" href="#排障指南" aria-label="Permalink to &quot;排障指南&quot;">​</a></h1><p>遇到问题先来对着症状查。大部分常见问题都能快速定位。</p><h2 id="访问入口域名没反应" tabindex="-1">访问入口域名没反应 <a class="header-anchor" href="#访问入口域名没反应" aria-label="Permalink to &quot;访问入口域名没反应&quot;">​</a></h2><p><strong>症状：</strong> 浏览器输入域名后一直加载，最后超时。</p><p>按顺序检查：</p><ol><li><strong>DNS 是否生效</strong> — 在本地执行 <code>nslookup app.example.com</code>，看返回的 IP 是不是你的 VPS。刚添加的 DNS 记录可能需要几分钟到几小时才能全球生效。</li><li><strong>端口是否放行</strong> — 检查云服务商的安全组和 VPS 系统防火墙，确认监听端口已放行。HTTP 默认 80，HTTPS 默认 443。</li><li><strong>规则是否启用</strong> — 在面板里确认规则开关是开启状态。</li><li><strong>规则选了正确的 Agent 吗</strong> — 入口规则必须选实际在监听的那台机器的 Agent。</li></ol><h2 id="规则保存了但访问不到后端" tabindex="-1">规则保存了但访问不到后端 <a class="header-anchor" href="#规则保存了但访问不到后端" aria-label="Permalink to &quot;规则保存了但访问不到后端&quot;">​</a></h2><p><strong>症状：</strong> 浏览器显示 502 或连接被拒绝。</p><ol><li><p><strong>节点能不能访问后端</strong> — SSH 到运行规则的节点上执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://原站地址</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果不通，说明节点到后端的网络有问题。先把网络搞通再继续。</p></li><li><p><strong>后端协议和端口填对了吗</strong> — 检查规则里的后端地址：协议是 <code>http://</code> 还是 <code>https://</code>？端口号是不是对的？</p></li><li><p><strong>后端是否限制了反代</strong> — 有些后端会检查 Host 头、IP 地区或 User-Agent，可能需要在规则的高级设置里调整请求头。</p></li></ol><h2 id="https-访问失败" tabindex="-1">HTTPS 访问失败 <a class="header-anchor" href="#https-访问失败" aria-label="Permalink to &quot;HTTPS 访问失败&quot;">​</a></h2><p><strong>症状：</strong> <code>https://</code> 打不开，但 <code>http://</code> 可以。</p><ol><li>先用 HTTP 验证链路是通的，再启用 HTTPS。</li><li>去面板的 <strong>基础设施 → 证书管理</strong> 查看证书状态。如果签发失败，点重试。</li><li>确认 443 端口已在防火墙放行。</li><li>ACME 验证要求域名解析到运行规则的 Agent 节点，确认 DNS 没问题。</li></ol><h2 id="http-规则和-l4-规则怎么选" tabindex="-1">HTTP 规则和 L4 规则怎么选？ <a class="header-anchor" href="#http-规则和-l4-规则怎么选" aria-label="Permalink to &quot;HTTP 规则和 L4 规则怎么选？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>选哪个</th></tr></thead><tbody><tr><td>反代 Web 服务、Emby/Jellyfin、网站</td><td>HTTP 规则</td></tr><tr><td>转发 TCP/UDP 端口、游戏服务器、数据库</td><td>L4 规则</td></tr><tr><td>需要 Relay 隧道中转</td><td>HTTP 规则 + Relay 或 L4 规则 + Relay</td></tr></tbody></table><p>HTTP 规则理解域名、路径、HTTP 头，适合浏览器访问。L4 规则只转发端口流量，适合非 Web 协议。</p><h2 id="何时关闭-302-307-重定向改写" tabindex="-1">何时关闭 302/307 重定向改写？ <a class="header-anchor" href="#何时关闭-302-307-重定向改写" aria-label="Permalink to &quot;何时关闭 302/307 重定向改写？&quot;">​</a></h2><p>HTTP 规则默认把后端的跳转地址改写为你的入口域名，大多数情况下这是对的。以下场景需要关掉：</p><ul><li>CDN 回源需要保留原始地址</li><li>OAuth 回调需要原样传递</li><li>多跳转链接需要客户端直接访问中间地址</li></ul><p>关闭位置：HTTP 规则编辑页的「代理 302/307 重定向」选项。</p><h2 id="证书要手动申请吗" tabindex="-1">证书要手动申请吗？ <a class="header-anchor" href="#证书要手动申请吗" aria-label="Permalink to &quot;证书要手动申请吗？&quot;">​</a></h2><p>不需要。HTTP 规则保存后，Agent 会自动用 HTTP-01 方式申请证书，全程无需人工干预。</p><p>以下情况才需要手动处理：</p><ul><li>VPS 无法开放 80 端口 → 配置 Cloudflare DNS-01</li><li>需要通配符证书（<code>*.example.com</code>）→ DNS-01</li><li>已有商业证书 → 手动上传</li></ul><p>详见 <a href="./../guides/certificates">证书与 HTTPS</a>。</p><h2 id="local-agent-和远程-agent-的区别" tabindex="-1">local Agent 和远程 Agent 的区别？ <a class="header-anchor" href="#local-agent-和远程-agent-的区别" aria-label="Permalink to &quot;local Agent 和远程 Agent 的区别？&quot;">​</a></h2><p><strong>local Agent</strong> 是 Docker Compose 自带的，和控制面跑在同一个容器里。一台 VPS 做反代时所有规则选 <code>local</code> 就行。</p><p><strong>远程 Agent</strong> 用在多台服务器的场景——分散代理负载、不同地区提供入口、暴露内网服务。远程 Agent 主动连接控制面拉配置，不需要控制面向 Agent 开放入站端口。</p><h2 id="流量额度超了怎么办" tabindex="-1">流量额度超了怎么办？ <a class="header-anchor" href="#流量额度超了怎么办" aria-label="Permalink to &quot;流量额度超了怎么办？&quot;">​</a></h2><p>流量策略中开启「超额阻断」后，节点达到月度额度会被阻断。被阻断的节点在下个计费周期自动恢复。你也可以手动调高额度或关闭超额阻断。</p><p>详见 <a href="./../guides/traffic-quota">流量额度</a>。</p><h2 id="数据库可以换吗" tabindex="-1">数据库可以换吗？ <a class="header-anchor" href="#数据库可以换吗" aria-label="Permalink to &quot;数据库可以换吗？&quot;">​</a></h2><p>可以。默认 SQLite 适合个人和小团队。数据量大了可以切换到 PostgreSQL 或 MySQL：</p><ol><li>设置 <code>NRE_DATABASE_DRIVER</code> 和 <code>NRE_DATABASE_DSN</code> 环境变量</li><li>用 <code>migrate-storage</code> 命令迁移数据</li></ol><p>详见 <a href="./migration">数据迁移</a>。</p><h2 id="为什么默认用-host-网络" tabindex="-1">为什么默认用 host 网络？ <a class="header-anchor" href="#为什么默认用-host-网络" aria-label="Permalink to &quot;为什么默认用 host 网络？&quot;">​</a></h2><p>Docker bridge 网络在容器启动后不能动态新增端口映射，而 Agent 需要根据规则动态创建监听端口。host 网络让容器直接共享宿主机网络栈，端口管理完全灵活。代价是规则配置的端口直接占用宿主机端口，需要注意端口冲突。</p><h2 id="面板数据存在哪里" tabindex="-1">面板数据存在哪里？ <a class="header-anchor" href="#面板数据存在哪里" aria-label="Permalink to &quot;面板数据存在哪里？&quot;">​</a></h2><p>默认在 Compose 文件同级的 <code>./data</code> 目录。所有配置、证书、Agent 信息都在里面。<strong>请定期备份这个目录。</strong></p><h2 id="远程-agent-需要开放入站端口吗" tabindex="-1">远程 Agent 需要开放入站端口吗？ <a class="header-anchor" href="#远程-agent-需要开放入站端口吗" aria-label="Permalink to &quot;远程 Agent 需要开放入站端口吗？&quot;">​</a></h2><p>不需要。Agent 主动连接控制面（心跳拉取），控制面不会主动连 Agent。即使 Agent 在 NAT 或内网后面也能工作。</p><p>但代理规则本身的监听端口（80、443 或你指定的端口）仍需放行，否则访客进不来。</p>',41)])])}const u=a(r,[["render",i]]);export{g as __pageData,u as default};
